use std::sync::{Arc, Mutex, RwLock};
use std::thread;
use std::collections::HashMap;

#[derive(Debug)]
struct InventoryItem {
    stock: i32,
    name: String,
}

#[derive(Debug)]
pub struct Inventory {
    items: RwLock<HashMap<String, InventoryItem>>,
}

impl Inventory {
    pub fn new() -> Self {
        Inventory {
            items: RwLock::new(HashMap::new()),
        }
    }

    pub fn add_item(&self, name: String, stock: i32) {
        let mut items = self.items.write().unwrap();
        items.insert(name, InventoryItem { stock, name });
    }

    pub fn check_stock(&self, item_name: &str) -> Option<i32> {
        let items = self.items.read().unwrap();
        items.get(item_name).map(|item| item.stock)
    }

    pub fn decrement_stock(&self, item_name: &str, quantity: i32) -> bool {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(item_name) {
            if item.stock >= quantity {
                item.stock -= quantity;
                return true;
            }
        }
        false
    }

    pub fn update_stock(&self, item_name: &str, new_stock: i32) -> bool {
        let mut items = self.items.write().unwrap();
        if let Some(item) = items.get_mut(item_name) {
            item.stock = new_stock;
            true
        } else {
            false
        }
    }
}

pub fn concurrent_inventory_update(
    inventory: Arc<Inventory>,
    item_name: String,
    num_threads: usize,
    quantity_per_thread: i32,
) {
    let mut handles = vec![];

    for _ in 0..num_threads {
        let inventory_clone = Arc::clone(&inventory);
        let item_name_clone = item_name.clone();

        let handle = thread::spawn(move || {
            let mut attempts = 0;
            let max_attempts = 10;
            
            while attempts < max_attempts {
                if inventory_clone.decrement_stock(&item_name_clone, quantity_per_thread) {
                    break;
                }
                attempts += 1;
                thread::sleep(std::time::Duration::from_millis(10));
            }
        });

        handles.push(handle);
    }

    for handle in handles {
        handle.join().unwrap();
    }
}